SELECT *
FROM ts_user_image_asset
WHERE user_id = #{query.userId}

    AND (
        file_name LIKE CONCAT('%', #{query.keyword}, '%')
        OR file_url LIKE CONCAT('%', #{query.keyword}, '%')
    )


    AND source_type = #{query.sourceType}



        AND status = #{query.status}


        AND status != 0


ORDER BY updated_at DESC, id DESC

SELECT *
FROM ts_user_image_asset
WHERE id = #{id}
  AND user_id = #{userId}
  AND status != 0
LIMIT 1
